struct EXTERN ASN1T_PLMN_Identity {
   OSUINT32 numocts;
   OSOCTET data[3];
   // ctors
   ASN1T_PLMN_Identity () : numocts(0) {}
   ASN1T_PLMN_Identity (OSUINT32 _numocts, const OSOCTET* _data) :
      numocts (_numocts) {
      OSCRTLSAFEMEMCPY (data, sizeof(data), _data, numocts);
   }
   ASN1T_PLMN_Identity (const char* cstring) {
      if (!OS_ISEMPTY (cstring)) {
         numocts = (OSUINT32)(OSRTMIN ((OSCRTLSTRLEN(cstring)+1), sizeof(data)));
         OSCRTLSAFEMEMCPY (data, numocts, cstring, numocts);
      }
      else numocts = 0;
   }
   // assignment operators
   ASN1T_PLMN_Identity& operator= (const char* cstring) {
      if (!OS_ISEMPTY (cstring)) {
         numocts = (OSUINT32)(OSRTMIN ((OSCRTLSTRLEN(cstring)+1), sizeof(data)));
         OSCRTLSAFEMEMCPY (data, numocts, cstring, numocts);
      }
      else numocts = 0;
      return *this;
   }
} ;

